  1→/**
  2→ * Trace Writer — Async trace capture for LLM proxy calls
  3→ *
  4→ * Creates llm_call trace nodes in SurrealDB after stream/response completion.
  5→ * All graph writes are async via deps.inflight.track() to avoid blocking
  6→ * response delivery.
  7→ *
  8→ * Port: (TraceData, Dependencies) -> Promise<void>
  9→ * Side effects: SurrealDB writes (boundary adapter)
 10→ */
 11→
 12→import { RecordId } from "surrealdb";
 13→import { calculateCost, type TokenUsage } from "./cost-calculator";
 14→import { getModelPricing } from "./pricing-table";
 15→import { withRetry } from "./retry";
 16→import type { Surreal } from "surrealdb";
 17→import { log } from "../telemetry/logger";
 18→
 19→// ---------------------------------------------------------------------------
 20→// Types
 21→// ---------------------------------------------------------------------------
 22→
 23→export type TraceData = {
 24→  readonly model: string;
 25→  readonly inputTokens: number;
 26→  readonly outputTokens: number;
 27→  readonly cacheCreationTokens: number;
 28→  readonly cacheReadTokens: number;
 29→  readonly stopReason?: string;
 30→  readonly latencyMs: number;
 31→  readonly workspaceId?: string;
 32→  readonly identityId?: string;
 33→  readonly sessionId?: string;
 34→  readonly taskId?: string;
 35→  readonly requestId?: string;
 36→  readonly policyDecision?: {
 37→    readonly decision: "pass" | "deny";
 38→    readonly policy_refs: string[];
 39→    readonly reason?: string;
 40→    readonly timestamp: string;
 41→  };
 42→  // Intelligence metadata (context injection)
 43→  readonly intelligenceMetadata?: {
 44→    readonly brain_context_injected: boolean;
 45→    readonly brain_context_decisions: number;
 46→    readonly brain_context_learnings: number;
 47→    readonly brain_context_observations: number;
 48→    readonly brain_context_tokens_est: number;
 49→  };
 50→  // Response content (opaque capture per ADR-051)
 51→  readonly responseContent?: {
 52→    readonly content_blocks: Array<{ type: string; text?: string; id?: string; name?: string; input?: unknown }>;
 53→    readonly stop_reason: string;
 54→    readonly usage: {
 55→      readonly input_tokens: number;
 56→      readonly output_tokens: number;
 57→      readonly cache_creation_tokens?: number;
 58→      readonly cache_read_tokens?: number;
 59→    };
 60→  };
 61→};
 62→
 63→type TraceDependencies = {
 64→  readonly surreal: Surreal;
 65→};
 66→
 67→// ---------------------------------------------------------------------------
 68→// Trace Node Creation
 69→// ---------------------------------------------------------------------------
 70→
 71→async function createTraceNode(
 72→  surreal: Surreal,
 73→  traceId: string,
 74→  data: TraceData,
 75→  costUsd: number,
 76→): Promise<RecordId> {
 77→  const traceRecord = new RecordId("trace", traceId);
 78→
 79→  const content: Record<string, unknown> = {
 80→    type: "llm_call",
 81→    model: data.model,
 82→    provider: "anthropic",
 83→    input_tokens: data.inputTokens,
 84→    output_tokens: data.outputTokens,
 85→    cache_creation_tokens: data.cacheCreationTokens,
 86→    cache_read_tokens: data.cacheReadTokens,
 87→    cost_usd: costUsd,
 88→    latency_ms: Math.round(data.latencyMs),
 89→    stop_reason: data.stopReason ?? "end_turn",
 90→    created_at: new Date(),
 91→  };
 92→
 93→  // Set workspace directly on the trace node when known
 94→  if (data.workspaceId) {
 95→    content.workspace = new RecordId("workspace", data.workspaceId);
 96→  }
 97→
 98→  // Set actor directly on the trace node (Brain auth mode)
 99→  if (data.identityId) {
100→    content.actor = new RecordId("identity", data.identityId);
101→  }
102→
103→  if (data.requestId) {
104→    content.request_id = data.requestId;
105→  }
106→
107→  // Store intelligence metadata in FLEXIBLE input field
108→  if (data.intelligenceMetadata) {
109→    content.input = {
110→      brain_context_injected: data.intelligenceMetadata.brain_context_injected,
111→      brain_context_decisions: data.intelligenceMetadata.brain_context_decisions,
112→      brain_context_learnings: data.intelligenceMetadata.brain_context_learnings,
113→      brain_context_observations: data.intelligenceMetadata.brain_context_observations,
114→      brain_context_tokens_est: data.intelligenceMetadata.brain_context_tokens_est,
115→    };
116→  }
117→
118→  // Store response content in FLEXIBLE output field (opaque capture per ADR-051)
119→  if (data.responseContent) {
120→    content.output = data.responseContent;
121→  }
122→
123→  if (data.policyDecision) {
124→    content.policy_decision = data.policyDecision;
125→  }
126→
127→  await surreal.query(`CREATE $trace CONTENT $content;`, {
128→    trace: traceRecord,
129→    content,
130→  });
131→
132→  return traceRecord;
133→}
134→
135→// ---------------------------------------------------------------------------
136→// Edge Creation
137→// ---------------------------------------------------------------------------
138→
139→async function createTraceEdges(
140→  surreal: Surreal,
141→  traceRecord: RecordId,
142→  data: TraceData,
143→): Promise<void> {
144→  // Always create workspace scope edge when workspace is known
145→  if (data.workspaceId) {
146→    const workspaceRecord = new RecordId("workspace", data.workspaceId);
147→    await surreal.query(
148→      `RELATE $trace->scoped_to->$workspace SET created_at = time::now();`,
149→      { trace: traceRecord, workspace: workspaceRecord },
150→    );
151→  }
152→
153→  // Create session invocation edge when session is resolved.
154→  // NOTE: `$session` is a SurrealDB protected variable — use `$sess` instead.
155→  // The caller must resolve the effective session ID to an agent_session PK
156→  // before passing it here.
157→  if (data.sessionId) {
158→    const sessionRecord = new RecordId("agent_session", data.sessionId);
159→    await surreal.query(
160→      `RELATE $sess->invoked->$trace SET created_at = time::now();`,
161→      { sess: sessionRecord, trace: traceRecord },
162→    );
163→  }
164→
165→  // Create task attribution edge when task is resolved
166→  if (data.taskId) {
167→    const taskRecord = new RecordId("task", data.taskId);
168→    await surreal.query(
169→      `RELATE $trace->attributed_to->$task SET created_at = time::now();`,
170→      { trace: traceRecord, task: taskRecord },
171→    );
172→  }
173→
174→  // Create governed_by edges for policy audit trail
175→  if (data.policyDecision) {
176→    for (const policyId of data.policyDecision.policy_refs) {
177→      const policyRecord = new RecordId("policy", policyId);
178→      await surreal.query(
179→        `RELATE $trace->governed_by->$policy SET created_at = time::now(), decision = $decision;`,
180→        {
181→          trace: traceRecord,
182→          policy: policyRecord,
183→          decision: data.policyDecision.decision,
184→        },
185→      );
186→    }
187→  }
188→}
189→
190→// ---------------------------------------------------------------------------
191→// Public API
192→// ---------------------------------------------------------------------------
193→
194→/**
195→ * Capture an LLM call trace asynchronously.
196→ *
197→ * Computes cost from the pricing table, creates a trace node, and
198→ * establishes relationship edges. All operations are retried 3x with
199→ * exponential backoff. On persistent failure, logs structured output
200→ * instead of throwing.
201→ *
202→ * This function returns a Promise that should be tracked via
203→ * deps.inflight.track() — it must NOT block response delivery.
204→ */
205→export async function captureTrace(
206→  data: TraceData,
207→  deps: TraceDependencies,
208→): Promise<void> {
209→  const traceId = crypto.randomUUID();
210→
211→  // Compute cost from pricing table (pure)
212→  const usage: TokenUsage = {
213→    inputTokens: data.inputTokens,
214→    outputTokens: data.outputTokens,
215→    cacheCreationTokens: data.cacheCreationTokens,
216→    cacheReadTokens: data.cacheReadTokens,
217→  };
218→  const pricing = getModelPricing(data.model);
219→  const costUsd = calculateCost(usage, pricing);
220→
221→  try {
222→    // Create trace node with retry
223→    const traceRecord = await withRetry(
224→      () => createTraceNode(deps.surreal, traceId, data, costUsd),
225→      "trace_node_create",
226→    );
227→
228→    // Create edges with retry
229→    await withRetry(
230→      () => createTraceEdges(deps.surreal, traceRecord, data),
231→      "trace_edges_create",
232→    );
233→
234→    log.info("proxy.trace.captured", "LLM call trace captured", {
235→      trace_id: traceId,
236→      model: data.model,
237→      cost_usd: costUsd,
238→      workspace_id: data.workspaceId,
239→    });
240→  } catch (error) {
241→    // Fallback: structured log output when graph write fails after retries
242→    log.error("proxy.trace.write_failed", "Failed to write trace after retries, logging fallback", error);
243→    log.info("proxy.trace.fallback", "Trace data (graph write failed)", {
244→      trace_id: traceId,
245→      model: data.model,
246→      input_tokens: data.inputTokens,
247→      output_tokens: data.outputTokens,
248→      cache_creation_tokens: data.cacheCreationTokens,
249→      cache_read_tokens: data.cacheReadTokens,
250→      cost_usd: costUsd,
251→      latency_ms: Math.round(data.latencyMs),
252→      stop_reason: data.stopReason,
253→      workspace_id: data.workspaceId,
254→      identity_id: data.identityId,
255→      session_id: data.sessionId,
256→      task_id: data.taskId,
257→    });
258→  }
259→}
